      } catch (error) {
        timingEnd(rule.alias);
        wrapLintError(error, rule.getName());
      }
    } else {
      return [text, false];
    }
  }

  static getBuilderByName(name: string): RuleBuilderBase {
    return RuleBuilderBase.#ruleBuilderMap.get(name);
  }

